COLS = [
    "season","round","region","team_a","team_b","seed_a","seed_b",
    "kenpom_em_a","kenpom_em_b","elo_a","elo_b","market_prob_a",
    "adj_off_a","adj_off_b","adj_def_a","adj_def_b",
    "tempo_a","tempo_b","efg_a","efg_b","def_efg_a","def_efg_b",
    "tov_a","tov_b","orb_a","orb_b",
    "ft_rate_a","ft_rate_b","ft_pct_a","ft_pct_b",
    "three_pt_rate_a","three_pt_rate_b","sos_a","sos_b",
    "conf_power_a","conf_power_b","experience_a","experience_b",
    "team_a_won","source_conf","notes",
]

def load_dataframe() -> pd.DataFrame:
    rows = []
    for r in _RAW:
        row = list(r)
        # Ensure team_a_won is always in position 38 as int
        # Some rows had notes creep into wrong position — fix defensively
        won_val = row[38]
        if isinstance(won_val, int):
            pass  # correct
        elif isinstance(won_val, str) and won_val in ("0","1"):
            row[38] = int(won_val)
        else:
            # notes leaked into won slot — shouldn't happen but guard anyway
            row[38] = 1
        rows.append(row)
    df = pd.DataFrame(rows, columns=COLS)
    # coerce types
    df["team_a_won"] = pd.to_numeric(df["team_a_won"], errors="coerce").fillna(1).astype(int)
    # Derived columns
    df["market_prob_b"]   = 1 - df["market_prob_a"]
    df["elo_b"]           = df.apply(lambda r: 3200 - r.elo_a if r.elo_b == 0 else r.elo_b, axis=1)
    df["em_diff"]         = df.kenpom_em_a - df.kenpom_em_b
    df["elo_diff"]        = df.elo_a       - df.elo_b
    df["adj_off_diff"]    = df.adj_off_a   - df.adj_off_b
    df["adj_def_diff"]    = df.adj_def_a   - df.adj_def_b   # lower = better so negative = A better
    df["efg_diff"]        = df.efg_a       - df.efg_b
    df["def_efg_diff"]    = df.def_efg_a   - df.def_efg_b   # lower def_efg = better
    df["tov_diff"]        = df.tov_a       - df.tov_b       # lower = better
    df["orb_diff"]        = df.orb_a       - df.orb_b
    df["ft_rate_diff"]    = df.ft_rate_a   - df.ft_rate_b
    df["ft_pct_diff"]     = df.ft_pct_a    - df.ft_pct_b
    df["tempo_diff"]      = df.tempo_a     - df.tempo_b
    df["sos_diff"]        = df.sos_a       - df.sos_b
    df["three_pt_rate_diff"] = df.three_pt_rate_a - df.three_pt_rate_b
    df["seed_diff"]       = df.seed_a      - df.seed_b      # negative = A is lower seed (favored)
    df["fav_seed"]        = df[["seed_a","seed_b"]].min(axis=1)
    df["upset"]           = ((df.seed_a > df.seed_b) & (df.team_a_won == 1)) | \
                            ((df.seed_b > df.seed_a) & (df.team_a_won == 0))
    # Interaction features
    df["off_vs_def"]      = df.adj_off_a   * (1/df.adj_def_b.clip(lower=80))
    df["tov_matchup"]     = df.tov_a * df.tov_b  # both high = chaos
    df["orb_drb_interaction"] = df.orb_a * (1 - df.orb_b)  # A ORB vs B's implied DRB
    df["three_pt_variance"]   = (df.three_pt_rate_a + df.three_pt_rate_b) / 2  # game-level chaos
    df["em_sq"]           = df.em_diff ** 2
    df["elo_sq"]          = df.elo_diff ** 2
    return df

def get_seasons(df: pd.DataFrame = None):
    if df is None: df = load_dataframe()
    return sorted(df.season.unique().tolist())

def get_missingness(df: pd.DataFrame = None) -> pd.DataFrame:
    if df is None: df = load_dataframe()
    miss = df.isnull().sum()
    pct  = miss / len(df)
    return pd.DataFrame({"missing_count":miss,"missing_pct":pct}).query("missing_count > 0")

if __name__ == "__main__":
    df = load_dataframe()
    print(f"Version:  {DATA_VERSION}  |  Freeze: {FREEZE_POINT}")
    print(f"Games:    {len(df)}  |  Seasons: {get_seasons(df)}")
    print(f"Upsets:   {df.upset.sum()} / {len(df)} = {df.upset.mean():.1%}")
    print(f"Fav wins: {(df.team_a_won == (df.seed_a < df.seed_b).astype(int)).mean():.1%}  (team_a_won when A is fav)")
    print(f"\nActual fav-seed win rates:")
    for fs, grp in df.groupby("fav_seed"):
        fav_won = ((grp.seed_a == fs) & (grp.team_a_won == 1)) | ((grp.seed_b == fs) & (grp.team_a_won == 0))
        print(f"  Seed {int(fs):2d}: {fav_won.sum():3d}/{len(grp):3d} = {fav_won.mean():.1%}")
    miss = get_missingness(df)
    print(f"\nMissingness: {len(miss)} features with nulls")
    if len(miss): print(miss)
    print(f"\nColumns: {list(df.columns)}")


def load_symmetrized() -> pd.DataFrame:
    """
    Return dataset where every game appears twice:
      row 1: team_a=winner, team_b=loser, team_a_won=1
      row 2: team_a=loser,  team_b=winner, team_a_won=0
    This gives balanced labels for model training.
    """
    df = load_dataframe()
    orig = df.copy()
    flip = df.copy()

    # Explicit symmetric column pairs (only numeric feature pairs)
    PAIR_COLS = [
        ("seed_a",          "seed_b"),
        ("kenpom_em_a",     "kenpom_em_b"),
        ("elo_a",           "elo_b"),
        ("market_prob_a",   "market_prob_b"),
        ("adj_off_a",       "adj_off_b"),
        ("adj_def_a",       "adj_def_b"),
        ("tempo_a",         "tempo_b"),
        ("efg_a",           "efg_b"),
        ("def_efg_a",       "def_efg_b"),
        ("tov_a",           "tov_b"),
        ("orb_a",           "orb_b"),
        ("ft_rate_a",       "ft_rate_b"),
        ("ft_pct_a",        "ft_pct_b"),
        ("three_pt_rate_a", "three_pt_rate_b"),
        ("sos_a",           "sos_b"),
        ("conf_power_a",    "conf_power_b"),
        ("experience_a",    "experience_b"),
    ]

    flip["team_a"] = df["team_b"].copy()
    flip["team_b"] = df["team_a"].copy()
    for ca, cb in PAIR_COLS:
        if ca in df.columns and cb in df.columns:
            flip[ca] = df[cb].values.copy()
            flip[cb] = df[ca].values.copy()

    flip["team_a_won"] = 0

    # Fix signed diff columns
    for c in [col for col in df.columns if col.endswith("_diff")]:
        flip[c] = -df[c].values
    for c in ["em_diff","elo_diff","seed_diff"]:
        if c in df.columns:
            flip[c] = -df[c].values

    # Derived columns that depend on _a vs _b orientation
    flip["fav_seed"]  = df[["seed_a","seed_b"]].min(axis=1).values
    flip["upset"]     = ((flip["seed_a"] > flip["seed_b"]) & (flip["team_a_won"] == 1)) | \
                        ((flip["seed_b"] > flip["seed_a"]) & (flip["team_a_won"] == 0))

    out = pd.concat([orig, flip], ignore_index=True)
    # Coerce numeric types
    for c in ["experience_a","experience_b"]:
        out[c] = pd.to_numeric(out[c], errors="coerce").fillna(2.2)
    out = out.sample(frac=1, random_state=42).reset_index(drop=True)
    return out
